SELECT COUNT(*) AS TOTAL FROM LATTES_P_TEX_JOR PTJ JOIN LATTES_TEX_JOR TJ ON TJ.PK = PTJ.FK_TEX_JOR JOIN SERVIDOR S ON S.PK_SIAPE = PTJ.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('gyn') AND TJ.ANO = 2025 AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%administra%'